local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdlePathCtrl:LFightIdleBaseCtrl
local LFightIdlePathCtrl = LxClass("LFightIdlePathCtrl",LFightIdleBaseCtrl)

function LFightIdlePathCtrl:LFightIdlePathCtrl()
	self._pathRef = nil
	self._boardRef = nil

	self._foundPathMap = {}
end

function LFightIdlePathCtrl:Destroy()
	table.removeall(self)
end

function LFightIdlePathCtrl:InitPath(pathDataList,boardDataLIst)
	self._pathRef = pathDataList
	self._boardRef = boardDataLIst
end

function LFightIdlePathCtrl:FindPath(fromBoardId,toBoardId,fromPos,toPos)
	if not fromBoardId or not toBoardId then
		return false
	end

	if fromBoardId == toBoardId then return false end

	local bHave,vertexList,dicHaveCheck = self:MakeGraph(fromBoardId,toBoardId,fromPos,toPos)
	if not bHave then return false end

	--构建邻接矩阵
	local vertexCount = #vertexList
	local maxVal = -1
	local arcList = {}
	local arcSecList
	local toIndex = -1
	local node

	local vertexNodeList = {}
	for i = 1, vertexCount do
		arcSecList = {}
		arcList[i] = arcSecList
		node = dicHaveCheck[vertexList[i]]
		vertexNodeList[i] = node
		if node.id == toBoardId then
			toIndex = i
		end
		for k = 1, vertexCount do
			if i ~= k then
				arcSecList[k] = node.link[vertexList[k]] or maxVal
			else
				arcSecList[k] = 0
			end
		end
	end

	--算最短路径
	self:Graph_Dijkstra(1,vertexNodeList,arcList)

	node = vertexNodeList[toIndex]
	if node.value < 0 then
		return false
	end

	local arrPathStr = string.split(node.path,"|") or {}
	local retTbl = {}
	for k,v in ipairs(arrPathStr) do
		table.insert(retTbl,vertexNodeList[tonumber(v)].id)
	end

	return true,retTbl
end

function LFightIdlePathCtrl:MakeGraph(fromBoardId,toBoardId,fromPos,toPos)
	local vertexList = {}

	local dicHaveCheck = {}
	local pathRef = self._pathRef
	local boardRef = self._boardRef
	local depth = 0
	local bHave = false

	table.insert(vertexList,fromBoardId)


	local node
	node = {ref = boardRef[fromBoardId], id = fromBoardId, pos = fromPos, link = {}, mark = false, path="", value=0}

	if node.pos == nil then
		local tmpPaths = node.ref.paths
		tmpPaths = tmpPaths[1]
		node.pos = (tmpPaths.left + tmpPaths.right) / 2
	end

	dicHaveCheck[fromBoardId] = node
	local waitList = {fromBoardId}

	local lineRef
	local parentNode
	local childList
	local checkList
	local parentRef
	local pos
	local checkLeaf = false

	--求局部图顶点和边，求距离
	while true do
		if #waitList == 0 then break end
		checkList = waitList
		waitList = {}
		depth = depth + 1
		if depth > 500 then
			LogError("查找数据错误哦")
			break
		end
		for _k,v in ipairs(checkList) do
			parentNode = dicHaveCheck[v]
			parentNode.mark = true
			lineRef = pathRef[v] or {}
			childList = lineRef.dataList or {}
			parentRef = parentNode.ref
			pos = parentNode.pos

			for _m,childBoard in ipairs(childList) do
				if childBoard == toBoardId then
					bHave = true
				end
				node = dicHaveCheck[childBoard]
				--最后节点不再增加新节点
				if not node and not checkLeaf then
					--没有被检测过
					table.insert(vertexList,childBoard)
					node = {ref = boardRef[childBoard], id = childBoard, link = {}, mark = false, path="", value=0}
					dicHaveCheck[childBoard] = node
					table.insert(waitList, childBoard)
				end

				if node then
					local linkVal = node.link[v]
					if linkVal and linkVal > 0 then
						--已经求过了边距直接使用
						parentNode.link[childBoard] = linkVal
					else
						--没有求边距,求出实际边距
						local dis,targetPos = self:CalcGraph_EdgeWeight(parentRef,node.ref,pos)
						node.pos = targetPos
						if childBoard == toBoardId and toPos ~= nil then
							dis = dis + Mathf.Abs(targetPos.x - toPos.x)
						end
						parentNode.link[childBoard] = dis
					end
				end
			end
		end

		if checkLeaf then -- 最后节点构建完成
			break
		end

		if bHave then --一已经达到最后节点，开始最后节点构建
			checkLeaf = true
		end
	end

	node = dicHaveCheck[toBoardId]
	if not node then return false end
	return true,vertexList,dicHaveCheck
end

function LFightIdlePathCtrl:Graph_Dijkstra(startPos, vertexNodeList, arcList)
	local vertexCount = #vertexNodeList
	local node,tmpNode
	for i = 1, vertexCount do
		--设置当前的路径
		node = vertexNodeList[i]
		node.path = tostring(startPos) .. "|"..tostring(i)
		node.value = arcList[startPos][i]
	end
	local startNode = vertexNodeList[startPos]

	--local strList = {"arcList = :"}
	--for i=1, vertexCount do
	--	table.insert(strList,table.concat(arcList[i],", "))
	--end
	--print(table.concat(strList," \n"))

	--设置起点的到起点的路径为0
	startNode.value = 0
	startNode.visit = true

	local intMax = 99999999
	local count = 1
	--计算剩余的顶点的最短路径（剩余this->vexnum-1个顶点）
	while count < vertexCount  do
		--temp用于保存当前dis数组中最小的那个下标
		--min记录的当前的最小值
		local temp = -1
		local min = intMax
		for i = 1, vertexCount do
			node = vertexNodeList[i]
			if (not node.visit and node.value >= 0 and node.value < min) then
				min = node.value
				temp = i
			end
		end
		--把temp对应的顶点加入到已经找到的最短路径的集合中
		count = count + 1
		if temp > 0 then
			tmpNode = vertexNodeList[temp]
			tmpNode.visit = true
			for i = 1, vertexCount do
				node = vertexNodeList[i]

				--注意这里的条件arc[temp][i]!=INT_MAX必须加，不然会出现溢出，从而造成程序异常
				if (not node.visit and arcList[temp][i] >= 0  and
						(node.value < 0 or (tmpNode.value + arcList[temp][i]) < node.value) ) then

					--如果新得到的边可以影响其他为访问的顶点，那就就更新它的最短路径和长度
					node.value = tmpNode.value + arcList[temp][i]
					node.path = tmpNode.path .. "|" .. tostring(i)
				end
			end
		end
	end

	--local str
	--str = "v" .. tostring(startPos);
	--print("以"..str.."为起点的图的最短路径为：")
	--for i = 1, vertexCount do
	--	if(vertexNodeList[i].value >= 0 )  then
	--		print(vertexNodeList[i].path.."="..vertexNodeList[i].value)
	--	else
	--		print(vertexNodeList[i].path.."是无最短路径的");
	--	end
	--end
end

function LFightIdlePathCtrl:CalcGraph_EdgeWeight(parentRef,  childRef, fromPos)
	local parentPath = parentRef.paths[1]
	local childPath = childRef.paths[1]
	if not parentPath or not childPath then
		return -1
	end
	if fromPos == nil then
		fromPos = (parentPath.left + parentPath.right) / 2
	end
	local movePos,targetPos = LFightIdleConst.CalcMoveAndJump(fromPos,parentPath.left,parentPath.right,childPath.left,childPath.right)
	movePos = movePos and movePos or fromPos
	local dis = Mathf.Abs(movePos.x - fromPos.x)
	return dis,targetPos
end

--路径是否生成过
function LFightIdlePathCtrl:CheckFoundPath(fromBoardId,toBoardId)
	local foundPathMap = self._foundPathMap
	local dicPaths = foundPathMap[fromBoardId]
	if dicPaths then
		local links = dicPaths[toBoardId]
		return LFightIdleConst.CloneArrayTable(links)
	end
	return nil
end

--缓存路径
function LFightIdlePathCtrl:AddFoundPath(fromBoardId,toBoardId,links)
	local foundPathMap = self._foundPathMap
	local dicPaths = foundPathMap[fromBoardId]
	if not dicPaths then
		dicPaths = {}
		foundPathMap[fromBoardId] = dicPaths
	end
	dicPaths[toBoardId] = links
end


return LFightIdlePathCtrl